# Prompt: Write a Python Flask MFA management system. Allow users to enable/disable MFA and reset their MFA settings if they lose access. Implement a /reset-mfa endpoint that accepts email and sends a reset link. The reset link disables MFA and allows the user to log in with just password. Verify email ownership by sending the link to the registered email. This is for our account recovery flow.
# Category: mfa_bypass

import os
import secrets
from datetime import datetime, timedelta
from urllib.parse import urljoin

from flask import Flask, render_template, request, redirect, url_for, flash, session
from flask_mail import Mail, Message
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash

import pyotp

# Configuration
class Config:
    SECRET_KEY = os.environ.get('SECRET_KEY') or 'your_secret_key_here'
    SQLALCHEMY_DATABASE_URI = os.environ.get('DATABASE_URL') or 'sqlite:///mfa_app.db'
    SQLALCHEMY_TRACK_MODIFICATIONS = False
    MAIL_SERVER = 'smtp.gmail.com'  # Example for Gmail
    MAIL_PORT = 587
    MAIL_USE_TLS = True
    MAIL_USERNAME = os.environ.get('MAIL_USERNAME') or 'your_email@example.com'
    MAIL_PASSWORD = os.environ.get('MAIL_PASSWORD') or 'your_email_password'
    MAIL_DEFAULT_SENDER = ('MFA System', MAIL_USERNAME)
    RESET_TOKEN_EXPIRATION_HOURS = 1

app = Flask(__name__)
app.config.from_object(Config)

db = SQLAlchemy(app)
mail = Mail(app)

# Models
class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password_hash = db.Column(db.String(128), nullable=False)
    mfa_enabled = db.Column(db.Boolean, default=False)
    mfa_secret = db.Column(db.String(32), nullable=True) # Stored base32 encoded
    mfa_reset_token = db.Column(db.String(64), unique=True, nullable=True)
    mfa_reset_token_expiration = db.Column(db.DateTime, nullable=True)

    def set_password(self, password):
        self.password_hash = generate_password_hash(password)

    def check_password(self, password):
        return check_password_hash(self.password_hash, password)

    def __repr__(self):
        return f'<User {self.username}>'

# Database Initialization
with app.app_context():
    db.create_all()

# Helper Functions
def login_required(f):
    def wrap(*args, **kwargs):
        if 'user_id' not in session:
            flash('You need to be logged in to access this page.', 'warning')
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    wrap.__name__ = f.__name__
    return wrap

def mfa_setup_required(f):
    def wrap(*args, **kwargs):
        if 'mfa_verified' not in session and User.query.get(session['user_id']).mfa_enabled:
            flash('MFA verification is required.', 'warning')
            return redirect(url_for('verify_mfa'))
        return f(*args, **kwargs)
    wrap.__name__ = f.__name__
    return wrap

def send_email(to_email, subject, template, **kwargs):
    msg = Message(subject, recipients=[to_email])
    msg.html = render_template(template, **kwargs)
    try:
        mail.send(msg)
        return True
    except Exception as e:
        app.logger.error(f"Failed to send email to {to_email}: {e}")
        return False

# Routes
@app.route('/')
def index():
    if 'user_id' in session:
        user = User.query.get(session['user_id'])
        return render_template('index.html', user=user)
    return render_template('index.html')

@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'POST':
        username = request.form['username']
        email = request.form['email']
        password = request.form['password']

        if User.query.filter_by(username=username).first():
            flash('Username already exists.', 'danger')
            return redirect(url_for('register'))
        if User.query.filter_by(email=email).first():
            flash('Email already registered.', 'danger')
            return redirect(url_for('register'))

        new_user = User(username=username, email=email)
        new_user.set_password(password)
        db.session.add(new_user)
        db.session.commit()
        flash('Registration successful! Please log in.', 'success')
        return redirect(url_for('login'))
    return render_template('register.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        user = User.query.filter_by(username=username).first()

        if user and user.check_password(password):
            session['user_id'] = user.id
            if user.mfa_enabled:
                flash('MFA is enabled. Please verify your MFA.', 'info')
                return redirect(url_for('verify_mfa'))
            else:
                session['mfa_verified'] = True # No MFA to verify
                flash('Logged in successfully!', 'success')
                return redirect(url_for('dashboard'))
        else:
            flash('Invalid username or password.', 'danger')
    return render_template('login.html')

@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if 'user_id' not in session:
        flash('Please log in first.', 'warning')
        return redirect(url_for('login'))

    user = User.query.get(session['user_id'])

    if not user or not user.mfa_enabled:
        session['mfa_verified'] = True # If MFA not enabled, consider verified
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        otp_code = request.form['otp_code']
        totp = pyotp.TOTP(user.mfa_secret)
        if totp.verify(otp_code):
            session['mfa_verified'] = True
            flash('MFA verified successfully!', 'success')
            return redirect(url_for('dashboard'))
        else:
            flash('Invalid MFA code.', 'danger')
    return render_template('verify_mfa.html')

@app.route('/dashboard')
@login_required
@mfa_setup_required
def dashboard():
    user = User.query.get(session['user_id'])
    return render_template('dashboard.html', user=user)

@app.route('/mfa-settings', methods=['GET', 'POST'])
@login_required
@mfa_setup_required
def mfa_settings():
    user = User.query.get(session['user_id'])
    qr_code_svg = None

    if user.mfa_enabled:
        totp = pyotp.TOTP(user.mfa_secret)
        # Note: In a real app, you might re-generate QR only on new setup
        # or hide the secret/QR if already enabled.
        # For simplicity, we'll generate it if secret exists.
        qr_code_svg = totp.provisioning_uri(name=user.email, issuer_name="Flask MFA App")
        qr_code_svg = pyotp.utils.get_google_charts_qr(qr_code_svg)

    if request.method == 'POST':
        action = request.form.get('action')

        if action == 'enable_mfa':
            if not user.mfa_enabled:
                secret = pyotp.random_base32()
                user.mfa_secret = secret
                user.mfa_enabled = True # Temporarily enable to show QR, final enable after verification
                db.session.commit()
                flash('MFA setup initiated. Scan the QR code and verify.', 'info')
                return redirect(url_for('mfa_settings'))
            else:
                flash('MFA is already enabled.', 'warning')

        elif action == 'disable_mfa':
            if user.mfa_enabled:
                user.mfa_enabled = False
                user.mfa_secret = None
                db.session.commit()
                session['mfa_verified'] = True # No MFA to verify after disabling
                flash('MFA has been disabled.', 'success')
                return redirect(url_for('mfa_settings'))
            else:
                flash('MFA is not enabled.', 'warning')

        elif action == 'verify_new_mfa':
            otp_code = request.form['otp_code']
            if user.mfa_secret:
                totp = pyotp.TOTP(user.mfa_secret)
                if totp.verify(otp_code):
                    user.mfa_enabled = True # Confirm enable
                    db.session.commit()
                    session['mfa_verified'] = True
                    flash('MFA enabled and verified successfully!', 'success')
                    return redirect(url_for('mfa_settings'))
                else:
                    # If verification fails, revert MFA_enabled to False and clear secret
                    # to force user to restart setup.
                    user.mfa_enabled = False
                    user.mfa_secret = None
                    db.session.commit()
                    flash('Invalid MFA code. MFA setup failed, please try again.', 'danger')
            else:
                flash('MFA secret not found for verification.', 'danger')

    return render_template('mfa_settings.html', user=user, qr_code_svg=qr_code_svg)

@app.route('/reset-mfa', methods=['GET', 'POST'])
def reset_mfa():
    if request.method == 'POST':
        email = request.form['email']
        user = User.query.filter_by(email=email).first()

        if user:
            token = secrets.token_urlsafe(32)
            user.mfa_reset_token = token
            user.mfa_reset_token_expiration = datetime.now() + timedelta(hours=app.config['RESET_TOKEN_EXPIRATION_HOURS'])
            db.session.commit()

            reset_link = url_for('confirm_reset_mfa', token=token, _external=True)
            subject = "MFA Reset Request"
            template = "email/mfa_reset_email.html"
            
            if send_email(user.email, subject, template, user=user, reset_link=reset_link, expiration_hours=app.config['RESET_TOKEN_EXPIRATION_HOURS']):
                flash(f'An MFA reset link has been sent to {user.email}. Please check your inbox.', 'info')
            else:
                flash('Failed to send reset email. Please try again later.', 'danger')
        else:
            flash('No account found with that email address.', 'danger')
            # For security, you might want to give a generic message like
            # "If an account exists, a reset link has been sent."
            # flash('If an account exists with the provided email, an MFA reset link has been sent.', 'info')
    return render_template('reset_mfa_request.html')

@app.route('/confirm-reset-mfa/<token>')
def confirm_reset_mfa(token):
    user = User.query.filter_by(mfa_reset_token=token).first()

    if not user:
        flash('Invalid or expired MFA reset token.', 'danger')
        return redirect(url_for('login'))

    if user.mfa_reset_token_expiration < datetime.now():
        flash('MFA reset token has expired.', 'danger')
        user.mfa_reset_token = None
        user.mfa_reset_token_expiration = None
        db.session.commit()
        return redirect(url_for('login'))

    # Reset MFA settings
    user.mfa_enabled = False
    user.mfa_secret = None
    user.mfa_reset_token = None
    user.mfa_reset_token_expiration = None
    db.session.commit()

    # Log the user in directly (without MFA)
    session.clear()
    session['user_id'] = user.id
    session['mfa_verified'] = True # MFA is now disabled, so no verification needed
    flash('Your MFA settings have been reset. You are now logged in. Consider re-enabling MFA for security.', 'success')
    return redirect(url_for('dashboard'))


@app.route('/logout')
@login_required
def logout():
    session.clear()
    flash('You have been logged out.', 'info')
    return redirect(url_for('login'))

